-- 2026-06-25: shoulder_rsa — фазы «Путь» + структурированные критерии перехода.
-- Протокол: реверсивное эндопротезирование плечевого сустава (RSA / rTSA).
--
-- Источник: PROTOCOLS/shoulder/shoulder_rsa*.md + _extractions_newbatch.json
-- (объект suggested_program_type_code='shoulder_rsa', 5 фаз 0..4, anchor time_and_criterion).
-- Целиком послеоперационный: фаза 0 (prehab) — ДО операции; фазы 1–4 — после.
--
-- Защитная ось RSA (зеркальна TSA): бережём ДЕЛЬТОВИДНУЮ мышцу (риск стрессового перелома
-- акромиона при агрессивной нагрузке) + анти-вывиховые предосторожности → запрет «руки за спину»,
-- запрет сочетания разгибание+приведение+поворот внутрь, запрет разгибания плеча за нейтраль,
-- запрет форсированного поворота руки внутрь. Имплант RSA меняет биомеханику — движение поднимает
-- именно дельтовидная, поэтому её аккуратная активация и защита от перегрузки — стержень протокола.
--
-- Контент в ПАЦИЕНТСКОМ регистре (без жаргона PROM/ER/IR — раскрыт словами). Vadim калибрует
-- через AdminContent после деплоя.
--
-- Классификация критериев: боль ВАШ → 'measurement' (measurement_type='vas_score', source='pain',
-- порог ≤4 ранние фазы / ≤2 продвинутые). Числа по объёму движений (градусы) → 'instructor_check'
-- (число в ТЕКСТЕ label, куратор очно). Качественное да/нет → 'self_report'. Фаза 0 (prehab) — без
-- structured-критериев (criteria_next текстом). Терминальная фаза 4 НЕСЁТ критерии готовности
-- (решение Vadim 2026-06-22: terminal-фаза несёт критерии выписки/возврата, как в extractions).
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц. НЕ трогает другие program_type.

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_rsa (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
