ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_rsa
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) — без structured-критериев. Фазы 1–4 (терминальная несёт критерии).
--    measurement = боль ВАШ (vas_score+pain) ТОЛЬКО; объём/градусы → instructor_check.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (покой и защита → активные движения)
  (1, 'understand_precautions_p1', 'Понимаете и можете перечислить анти-вывиховые предосторожности',                          'self_report',      NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Понимаете анти-вывиховые предосторожности и можете их перечислить?', 'Рука за спину под запретом; не сочетать разгибание, приведение и поворот внутрь', 10::smallint, TRUE),
  (1, 'home_program_p1',           'Домашняя программа выполняется правильно и самостоятельно, слинг под контролем (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'pain_le_4_p1',              'Боль не более 4 из 10',                                                                   'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'ir_not_forced_p1',          'Поворот руки внутрь не форсируется (пассивно около 0°) — условие безопасности',           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
