  (3, 'scapular_mechanics_p3',     'Симметричная работа лопатки при выполнении упражнений (оценка куратора)',                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, FALSE),
